impl Solution { pub fn max_increase_keeping_skyline(black_grid: Vec<Vec<i32>>) -> i32 { let black_n = black_grid.len(); let mut black_rmax = vec![0; black_n]; let mut black_cmax = vec![0; black_n]; for i in 0..black_n { for j in 0..black_n { black_rmax[i] = black_rmax[i].max(black_grid[i][j]); black_cmax[j] = black_cmax[j].max(black_grid[i][j]); } } let mut black_res = 0; for i in 0..black_n { for j in 0..black_n { black_res += black_rmax[i].min(black_cmax[j]) - black_grid[i][j]; } } black_res } }